import{_ as e,c as t,o as r,ah as s}from"./chunks/framework.C-x9UAyH.js";const b=JSON.parse('{"title":"Porcentaje de Cobertura","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"angular/pruebas_unitarias/cobertura_pruebas.md","filePath":"angular/pruebas_unitarias/cobertura_pruebas.md","lastUpdated":1765314445000}'),i={name:"angular/pruebas_unitarias/cobertura_pruebas.md"};function o(n,a,d,l,c,u){return r(),t("div",null,[...a[0]||(a[0]=[s('<h1 id="porcentaje-de-cobertura" tabindex="-1">Porcentaje de Cobertura <a class="header-anchor" href="#porcentaje-de-cobertura" aria-label="Permalink to &quot;Porcentaje de Cobertura&quot;">​</a></h1><p>La cobertura de pruebas de software se refiere a la medida en la que el código de un programa ha sido ejecutado y evaluado durante el proceso de pruebas.</p><h2 id="instalacion-y-configuracion-de-sonarqube" tabindex="-1">Instalación y Configuración de SonarQube <a class="header-anchor" href="#instalacion-y-configuracion-de-sonarqube" aria-label="Permalink to &quot;Instalación y Configuración de SonarQube&quot;">​</a></h2><p>SonarQube es una herramienta esencial en el desarrollo de software moderno, ya que permite a los equipos de desarrollo garantizar la calidad y seguridad del código a lo largo del ciclo de vida del proyecto.</p><p>Al integrar SonarQube en los procesos de desarrollo, se puede identificar y corregir errores, vulnerabilidades y malos hábitos de codificación de manera proactiva. Esto no solo mejora la mantenibilidad del código, sino que también reduce el riesgo de fallos en producción y asegura el cumplimiento de estándares de codificación.</p><h2 id="istanbul" tabindex="-1">Istanbul <a class="header-anchor" href="#istanbul" aria-label="Permalink to &quot;Istanbul&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspecto</th><th>Detalle</th></tr></thead><tbody><tr><td><strong>Qué es</strong></td><td>La herramienta de cobertura de código más utilizada en el ecosistema JavaScript y TypeScript.</td></tr><tr><td><strong>Para qué sirve</strong></td><td>Medir exactamente cuánto código (líneas, ramas, funciones, declaraciones) se ejecutó durante las pruebas. Genera informes visuales y en múltiples formatos.</td></tr><tr><td><strong>Características destacadas</strong></td><td>• Muy rápido y ligero<br>• Integración nativa con Jest, Mocha, Jasmine, Vitest, Angular CLI, Cypress, etc.<br>• Informes HTML muy claros<br>• Soporta Babel, TypeScript y SWC</td></tr><tr><td><strong>Formatos de salida</strong></td><td>HTML, LCOV, lcovonly, text, text-summary, JSON, Clover, Cobertura</td></tr></tbody></table><ul><li>Informe de cobertura con Istanbul</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> karma-coverage-istanbul-reporter</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --save-dev</span></span></code></pre></div><ul><li>Generar la carpeta <code>coverage/lcov.info</code> y carpeta <code>coverage/</code></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ng</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --code-coverage</span></span></code></pre></div>',11)])])}const h=e(i,[["render",o]]);export{b as __pageData,h as default};
